// Verify LINE signature over the RAW request body, then parse + filter events.
// Requires the Webhook node 'Raw Body' option ON, and n8n env
// NODE_FUNCTION_ALLOW_BUILTIN=crypto (or *) so require('crypto') works.
const crypto = require('crypto');

const wh = $('LINE Webhook').first();
const settings = $input.first().json;

// --- raw body string ---
let raw = '';
if (wh.binary && wh.binary.data && wh.binary.data.data) {
  raw = Buffer.from(wh.binary.data.data, 'base64').toString('utf8');
} else if (typeof wh.json.body === 'string') {
  raw = wh.json.body;
} else {
  // Fallback (will only match if body had no insignificant whitespace) — enable Raw Body!
  raw = JSON.stringify(wh.json.body || {});
}

const signature = (wh.json.headers || {})['x-line-signature'] || '';
const expected = crypto
  .createHmac('SHA256', settings.line_channel_secret || '')
  .update(raw)
  .digest('base64');

const valid = !!signature && signature === expected;

let events = [];
if (valid) {
  let parsed = {};
  try { parsed = JSON.parse(raw); } catch (e) {}
  events = (parsed.events || [])
    .filter(ev => ev.type === 'message' && ev.message && ev.message.type === 'text')
    .map(ev => ({
      userId: ev.source && ev.source.userId,
      text: (ev.message.text || '').trim(),
      eventId: ev.webhookEventId,
      replyToken: ev.replyToken
    }))
    .filter(e => e.userId && e.text && e.eventId);
}

return [{ json: { valid, events, settings } }];

// Fan out one item per text event for the core sub-workflow.
const { events, settings } = $json;
if (!events || !events.length) return [];
return events.map(event => ({ json: { event, settings } }));
